using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag in
        // the entry header. The legacy Java consumer reads names as Shift-JIS,
        // so we must explicitly specify that encoding to suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("Ð˜ÐÐ¥Ð/ÌÌ˜À.csv");  // Japanese path
        archive.CreateEntry("donnûˋes/rûˋsumûˋ.txt"); // French accented
